sql:
SELECT *
FROM model_logs
WHERE action = 'deployed';

SELECT metric_value 
FROM evaluations 
WHERE model_id = (SELECT model_id FROM models WHERE model_name = 'Sales Predictor');

SELECT models.model_name, datasets.dataset_name
FROM models
INNER JOIN datasets ON models.dataset_id = datasets.dataset_id;

SELECT DISTINCT m.model_name
FROM models m
JOIN evaluations e ON m.model_id = e.model_id;

SELECT parameter_value
FROM model_settings
WHERE parameter_name = 'segment_count';

SELECT setting_id, parameter_name, parameter_value, setting_description, default_value
FROM model_settings
WHERE model_id = 1;

SELECT models.model_name, features.feature_name
FROM models
JOIN features ON models.model_id = features.model_id;

external_knowledge:
- 'user_id = 0' refers to a specific user in the database who is performing training actions; 
- 'average evaluation score' refers to the average value of the evaluation metric across all evaluations for each model;
- 'latest release date' is the most recent date of release for the model versions.

